import React, { useEffect, useState } from "react";
import {
  Container,
  Card,
  Button,
  Table,
  Badge,
  Modal,
  Form,
  Row,
  Col,
  Alert,
  Spinner,
} from "react-bootstrap";
import { Link } from "react-router-dom";
import "../../styles/admin-main.css";

const API_BASE = "http://localhost:5000";

// Nếu backend của bạn mount admin event ở chỗ khác,
// chỉ cần sửa các endpoint này:
const EVENT_ENDPOINTS = {
  getAll: `${API_BASE}/api/events`,
  create: `${API_BASE}/api/events`,
  update: (id) => `${API_BASE}/api/events/${id}`,
  remove: (id) => `${API_BASE}/api/events/${id}`,
};

function AdminEventPage() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const [showModal, setShowModal] = useState(false);
  const [editingEvent, setEditingEvent] = useState(null);

  const [formData, setFormData] = useState({
    title: "",
    description: "",
    location: "",
    event_date: "",
    checkin_start_time: "",
    checkin_end_time: "",
    banner_image: "",
    status: "draft",
  });

  const token = localStorage.getItem("token");

  const authHeaders = {
    "Content-Type": "application/json",
    Authorization: `Bearer ${token}`,
  };

  const fetchEvents = async () => {
    try {
      setLoading(true);
      setError("");

      const response = await fetch(EVENT_ENDPOINTS.getAll);
      const data = await response.json();

      // backend có thể trả thẳng mảng hoặc object
      const eventList = Array.isArray(data) ? data : data.events || data.data || [];

      setEvents(eventList);
    } catch (err) {
      setError("Không thể tải danh sách sự kiện.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchEvents();
  }, []);

  const resetForm = () => {
    setFormData({
      title: "",
      description: "",
      location: "",
      event_date: "",
      checkin_start_time: "",
      checkin_end_time: "",
      banner_image: "",
      status: "draft",
    });
    setEditingEvent(null);
  };

  const handleOpenCreate = () => {
    resetForm();
    setShowModal(true);
  };

  const formatForDatetimeLocal = (value) => {
    if (!value) return "";
    return value.slice(0, 16);
  };

  const handleOpenEdit = (event) => {
    setEditingEvent(event);
    setFormData({
      title: event.title || "",
      description: event.description || "",
      location: event.location || "",
      event_date: formatForDatetimeLocal(event.event_date),
      checkin_start_time: formatForDatetimeLocal(event.checkin_start_time),
      checkin_end_time: formatForDatetimeLocal(event.checkin_end_time),
      banner_image: event.banner_image || "",
      status: event.status || "draft",
    });
    setShowModal(true);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    resetForm();
  };

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    setError("");
    setSuccess("");

    try {
      const isEditing = !!editingEvent;
      const url = isEditing
        ? EVENT_ENDPOINTS.update(editingEvent.id)
        : EVENT_ENDPOINTS.create;

      const method = isEditing ? "PUT" : "POST";

      const response = await fetch(url, {
        method,
        headers: authHeaders,
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Thao tác thất bại");
      }

      setSuccess(isEditing ? "Cập nhật sự kiện thành công!" : "Tạo sự kiện thành công!");
      handleCloseModal();
      fetchEvents();
    } catch (err) {
      setError(err.message || "Có lỗi xảy ra khi lưu sự kiện.");
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm("Bạn có chắc muốn xóa sự kiện này không?");
    if (!confirmDelete) return;

    try {
      setError("");
      setSuccess("");

      const response = await fetch(EVENT_ENDPOINTS.remove(id), {
        method: "DELETE",
        headers: authHeaders,
      });

      const data = await response.json().catch(() => ({}));

      if (!response.ok) {
        throw new Error(data.message || "Xóa sự kiện thất bại");
      }

      setSuccess("Xóa sự kiện thành công!");
      fetchEvents();
    } catch (err) {
      setError(err.message || "Không thể xóa sự kiện.");
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case "on_sale":
        return "success";
      case "upcoming":
        return "warning";
      case "draft":
        return "secondary";
      case "paused":
        return "dark";
      case "sold_out":
        return "danger";
      case "ended":
        return "primary";
      case "cancelled":
        return "outline-secondary";
      default:
        return "secondary";
    }
  };

  const renderStatusText = (status) => {
    switch (status) {
      case "draft":
        return "Bản nháp";
      case "upcoming":
        return "Sắp diễn ra";
      case "on_sale":
        return "Đang mở bán";
      case "paused":
        return "Tạm dừng";
      case "sold_out":
        return "Hết vé";
      case "ended":
        return "Đã kết thúc";
      case "cancelled":
        return "Đã hủy";
      default:
        return status;
    }
  };

  return (
    <div className="admin-page">
      <div className="admin-sidebar">
        <div className="admin-brand">
          <div className="admin-brand-logo">CT</div>
          <div>
            <h5>Concert Admin</h5>
            <span>Quản trị hệ thống</span>
          </div>
        </div>

        <div className="admin-menu">
          <p className="admin-menu-title">Tổng quan</p>
          <Link to="/admin" className="admin-menu-item">
            <span>📊</span> Dashboard
          </Link>

          <p className="admin-menu-title">Quản lý</p>
          <Link to="/admin/events" className="admin-menu-item active">
            <span>🎤</span> Quản lý sự kiện
          </Link>
          <button className="admin-menu-item">
            <span>🎟️</span> Quản lý loại vé
          </button>
          <button className="admin-menu-item">
            <span>🧾</span> Quản lý đơn hàng
          </button>
          <button className="admin-menu-item">
            <span>👥</span> Quản lý người dùng
          </button>
          <button className="admin-menu-item">
            <span>✅</span> Check-in
          </button>
        </div>
      </div>

      <div className="admin-content">
        <div className="admin-topbar">
          <div>
            <h2 className="admin-page-title">Quản lý sự kiện</h2>
            <p className="admin-page-subtitle">
              Tạo, cập nhật và quản lý toàn bộ sự kiện trong hệ thống
            </p>
          </div>

          <div className="admin-topbar-actions">
            <Button as={Link} to="/admin" variant="outline-dark">
              Quay lại Dashboard
            </Button>
            <Button className="admin-primary-btn" onClick={handleOpenCreate}>
              + Thêm sự kiện
            </Button>
          </div>
        </div>

        <Container fluid className="p-0">
          {error && <Alert variant="danger">{error}</Alert>}
          {success && <Alert variant="success">{success}</Alert>}

          <Card className="admin-card">
            <Card.Body>
              <div className="admin-card-header">
                <div>
                  <h5 className="mb-1">Danh sách sự kiện</h5>
                  <p className="text-muted mb-0">
                    Tổng số: {events.length} sự kiện
                  </p>
                </div>
              </div>

              {loading ? (
                <div className="admin-loading-box">
                  <Spinner animation="border" />
                  <p className="mt-3 mb-0">Đang tải dữ liệu sự kiện...</p>
                </div>
              ) : (
                <div className="table-responsive mt-3">
                  <Table hover className="admin-table align-middle">
                    <thead>
                      <tr>
                        <th>ID</th>
                        <th>Tên sự kiện</th>
                        <th>Địa điểm</th>
                        <th>Ngày diễn ra</th>
                        <th>Trạng thái</th>
                        <th>Thao tác</th>
                      </tr>
                    </thead>
                    <tbody>
                      {events.length > 0 ? (
                        events.map((event) => (
                          <tr key={event.id}>
                            <td>{event.id}</td>
                            <td>
                              <div className="fw-semibold">{event.title}</div>
                              <small className="text-muted">{event.slug}</small>
                            </td>
                            <td>{event.location}</td>
                            <td>
                              {event.event_date
                                ? new Date(event.event_date).toLocaleString("vi-VN")
                                : "—"}
                            </td>
                            <td>
                              <Badge bg={getStatusBadge(event.status)}>
                                {renderStatusText(event.status)}
                              </Badge>
                            </td>
                            <td>
                              <div className="admin-action-group">
                                <Button
                                  size="sm"
                                  variant="outline-primary"
                                  onClick={() => handleOpenEdit(event)}
                                >
                                  Sửa
                                </Button>
                                <Button
                                  size="sm"
                                  variant="outline-danger"
                                  onClick={() => handleDelete(event.id)}
                                >
                                  Xóa
                                </Button>
                              </div>
                            </td>
                          </tr>
                        ))
                      ) : (
                        <tr>
                          <td colSpan="6" className="text-center py-4 text-muted">
                            Chưa có sự kiện nào.
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </Table>
                </div>
              )}
            </Card.Body>
          </Card>
        </Container>
      </div>

      <Modal show={showModal} onHide={handleCloseModal} centered size="lg">
        <Modal.Header closeButton>
          <Modal.Title>
            {editingEvent ? "Cập nhật sự kiện" : "Thêm sự kiện mới"}
          </Modal.Title>
        </Modal.Header>

        <Form onSubmit={handleSubmit}>
          <Modal.Body>
            <Row>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Tên sự kiện</Form.Label>
                  <Form.Control
                    type="text"
                    name="title"
                    value={formData.title}
                    onChange={handleChange}
                    placeholder="Nhập tên sự kiện"
                    required
                  />
                </Form.Group>
              </Col>

              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Địa điểm</Form.Label>
                  <Form.Control
                    type="text"
                    name="location"
                    value={formData.location}
                    onChange={handleChange}
                    placeholder="Nhập địa điểm"
                    required
                  />
                </Form.Group>
              </Col>
            </Row>

            <Form.Group className="mb-3">
              <Form.Label>Mô tả</Form.Label>
              <Form.Control
                as="textarea"
                rows={3}
                name="description"
                value={formData.description}
                onChange={handleChange}
                placeholder="Nhập mô tả sự kiện"
              />
            </Form.Group>

            <Row>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Ngày diễn ra</Form.Label>
                  <Form.Control
                    type="datetime-local"
                    name="event_date"
                    value={formData.event_date}
                    onChange={handleChange}
                    required
                  />
                </Form.Group>
              </Col>

              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Trạng thái</Form.Label>
                  <Form.Select
                    name="status"
                    value={formData.status}
                    onChange={handleChange}
                  >
                    <option value="draft">Bản nháp</option>
                    <option value="upcoming">Sắp diễn ra</option>
                    <option value="on_sale">Đang mở bán</option>
                    <option value="paused">Tạm dừng</option>
                    <option value="sold_out">Hết vé</option>
                    <option value="ended">Đã kết thúc</option>
                    <option value="cancelled">Đã hủy</option>
                  </Form.Select>
                </Form.Group>
              </Col>
            </Row>

            <Row>
              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Bắt đầu check-in</Form.Label>
                  <Form.Control
                    type="datetime-local"
                    name="checkin_start_time"
                    value={formData.checkin_start_time}
                    onChange={handleChange}
                  />
                </Form.Group>
              </Col>

              <Col md={6}>
                <Form.Group className="mb-3">
                  <Form.Label>Kết thúc check-in</Form.Label>
                  <Form.Control
                    type="datetime-local"
                    name="checkin_end_time"
                    value={formData.checkin_end_time}
                    onChange={handleChange}
                  />
                </Form.Group>
              </Col>
            </Row>

            <Form.Group className="mb-3">
              <Form.Label>Banner image</Form.Label>
              <Form.Control
                type="text"
                name="banner_image"
                value={formData.banner_image}
                onChange={handleChange}
                placeholder="Nhập URL ảnh banner"
              />
            </Form.Group>
          </Modal.Body>

          <Modal.Footer>
            <Button variant="secondary" onClick={handleCloseModal}>
              Hủy
            </Button>
            <Button type="submit" className="admin-primary-btn" disabled={submitting}>
              {submitting ? "Đang lưu..." : editingEvent ? "Cập nhật" : "Tạo mới"}
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>
    </div>
  );
}

export default AdminEventPage;
